'use client';

import { ReactNode, useEffect, useState } from 'react';
import clsx from 'clsx';
import { Menu, X } from 'lucide-react';
import {
  portalShellClass,
  portalMainClass,
  portalMobileBarClass,
} from './portal-styles';

type PortalShellProps = {
  sidebar: ReactNode;
  children: ReactNode;
  className?: string;
  mobileTitle?: string;
};

export default function PortalShell({
  sidebar,
  children,
  className,
  mobileTitle = 'Menu',
}: PortalShellProps) {
  const [mobileOpen, setMobileOpen] = useState(false);

  useEffect(() => {
    if (!mobileOpen) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setMobileOpen(false);
    };
    document.body.style.overflow = 'hidden';
    window.addEventListener('keydown', onKey);
    return () => {
      document.body.style.overflow = '';
      window.removeEventListener('keydown', onKey);
    };
  }, [mobileOpen]);

  return (
    <div className={clsx(portalShellClass, className)}>
      <div className={portalMobileBarClass}>
        <button
          type="button"
          onClick={() => setMobileOpen(true)}
          className="p-2 rounded-lg hover:bg-white/10 transition-colors"
          aria-label="Open navigation menu"
        >
          <Menu size={22} />
        </button>
        <span className="text-sm font-semibold tracking-wide truncate">{mobileTitle}</span>
        <div className="w-10" aria-hidden />
      </div>

      {mobileOpen && (
        <button
          type="button"
          className="fixed inset-0 z-40 bg-black/50 lg:hidden"
          aria-label="Close navigation menu"
          onClick={() => setMobileOpen(false)}
        />
      )}

      <div
        className={clsx(
          'fixed inset-y-0 left-0 z-50 w-[min(16rem,88vw)] max-w-full transform transition-transform duration-300 ease-out lg:static lg:z-auto lg:w-auto lg:translate-x-0 lg:transform-none',
          mobileOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0',
        )}
      >
        <div className="relative h-full lg:h-auto">
          <button
            type="button"
            onClick={() => setMobileOpen(false)}
            className="lg:hidden absolute top-3 right-3 z-10 p-2 rounded-lg bg-brand-navy-800 text-white hover:bg-brand-navy-700"
            aria-label="Close menu"
          >
            <X size={18} />
          </button>
          <div
            className="h-full"
            onClick={(e) => {
              const target = e.target as HTMLElement;
              if (target.closest('a, button')) setMobileOpen(false);
            }}
          >
            {sidebar}
          </div>
        </div>
      </div>

      <main className={portalMainClass}>{children}</main>
    </div>
  );
}
